// ─── APP ─────────────────────────────────────────────────────────────────────
export default function App() {
  const [active, setActive] = useState("");

  useEffect(() => {
    const ids = ["hero","about","skills","projects","experience","certifications","contact"];
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach(e => { if (e.isIntersecting) setActive(e.target.id); });
      },
      { threshold: 0.4 }
    );
    ids.forEach(id => { const el = document.getElementById(id); if (el) obs.observe(el); });
    return () => obs.disconnect();
  }, []);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400;1,700&family=Karla:wght@300;400;500;600;700&display=swap');
        * { margin:0; padding:0; box-sizing:border-box; }
        html { scroll-behavior: smooth; } section, div[id] { scroll-margin-top: 64px; }
        body { font-family:'Karla',sans-serif; background:#05050f; color:#d4e8d8; }
        ::-webkit-scrollbar { width:5px; }
        ::-webkit-scrollbar-track { background:#05050f; }
        ::-webkit-scrollbar-thumb { background:#22c55e; border-radius:4px; }
        @keyframes float { from { transform:translateY(0) scale(1); } to { transform:translateY(-20px) scale(1.04); } }
        @keyframes bounce { 0%,100%{transform:translateX(-50%) translateY(0)} 50%{transform:translateX(-50%) translateY(8px)} }
        @keyframes spin { from { transform:rotate(0deg); } to { transform:rotate(360deg); } }
        @media(max-width:640px){
          .nav-links{ display:none !important; }
          .hamburger{ display:flex !important; flex-direction:column; }
        }
      `}</style>
      <Navbar active={active} />
      <Hero />
      <About />
      <Skills />
      <Projects />
      <Experience />
      <Certifications />
      <Contact />
      <Footer />
    </>
  );
}
